import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import L from 'leaflet';
import axios from 'axios';
import 'leaflet/dist/leaflet.css';

delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

const blueIcon = new L.Icon({
  iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-blue.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});

const redIcon = new L.Icon({
  iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-red.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});

const BinLocator = () => {
  const [position, setPosition] = useState([12.9716, 77.5946]);
  const [bins, setBins] = useState([]);
  const [loading, setLoading] = useState(true);

  const token = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1c2VySWQiOiI2OGY5MTY5NTIwN2FmZTMxZjRkZWM5NDYiLCJpYXQiOjE3NjExOTcwNDMsImV4cCI6MTc2MTgwMTg0M30.V0mAa2e0CxEaWpq5zu2QPYSdfzHsZLwlgcfeFrKaVs';
  const API_URL = 'http://localhost:5000/api/v1';

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          const { latitude, longitude } = pos.coords;
          setPosition([latitude, longitude]);
          fetchBins(latitude, longitude);
        },
        () => fetchBins(12.9716, 77.5946),
        { enableHighAccuracy: true }
      );
    }
  }, []);

  const fetchBins = async (lat, lng) => {
    try {
      setLoading(true);
      const res = await axios.get(
        `${API_URL}/bins/nearby?lat=${lat}&lng=${lng}&radius=15000`,
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setBins(res.data);
    } catch (err) {
      setBins([{
        id: '1',
        name: 'Bin A - MG Road',
        lat: 12.9750,
        lng: 77.6050,
        fillLevel: 45,
        address: 'MG Road, Bangalore'
      }]);
    } finally {
      setLoading(false);
    }
  };

  const updateBinFill = async (binId, newFill) => {
    try {
      await axios.post(
        `${API_URL}/bins/update/${binId}`,
        { fillLevel: parseInt(newFill) },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      alert('Bin updated!');
      fetchBins(position[0], position[1]); // REFRESH
    } catch (err) {
      alert('Update failed: ' + (err.response?.data?.error || err.message));
    }
  };

  if (loading) return <div className="loading">Detecting Location...</div>;

  return (
    <div className="map-page">
      <div className="map-header">
        <h2>E-Waste Bins Near You</h2>
        <p>{bins.length} bin(s) found</p>
      </div>
      <MapContainer center={position} zoom={14} className="map-container">
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
        <Marker position={position} icon={blueIcon}>
          <Popup><b>You Are Here</b></Popup>
        </Marker>
        {bins.map(bin => (
          <Marker key={bin.id} position={[bin.lat, bin.lng]} icon={redIcon}>
            // ADD THIS TO BinLocator.js (in Popup)
<Popup>
  <div className="bin-popup">
    <h4>{bin.name}</h4>
    <p><strong>Address:</strong> {bin.address}</p>
    <p><strong>Fill Level:</strong> {bin.fillLevel}%</p>
    <div className="fill-bar">
      <div style={{ width: `${bin.fillLevel}%` }}></div>
    </div>
    <button onClick={() => window.open(`https://www.google.com/maps/dir/${position[0]},${position[1]}/${bin.lat},${bin.lng}`)} className="directions-btn">
      GET DIRECTIONS
    </button>
    <div>
      <h5>Update Fill Level:</h5>
      <input type="number" id="fillLevel" min="0" max="100" defaultValue={bin.fillLevel} />
      <button onClick={() => updateBinFill(bin.id, document.getElementById('fillLevel').value)} className="update-btn">
        UPDATE
      </button>
    </div>
  </div>
</Popup>
            <Popup>
              <div className="bin-popup">
                <h4>{bin.name}</h4>
                <p><strong>Address:</strong> {bin.address}</p>
                <p><strong>Fill:</strong> {bin.fillLevel}%</p>
                <div className="fill-bar">
                  <div style={{ width: `${bin.fillLevel}%` }}></div>
                </div>
                <button 
                  onClick={() => window.open(`https://www.google.com/maps/dir/${position[0]},${position[1]}/${bin.lat},${bin.lng}`)}
                  className="directions-btn"
                >
                  GET DIRECTIONS
                </button>
              </div>
            </Popup>
          </Marker>
        ))}
      </MapContainer>
    </div>
  );
};

export default BinLocator;
